func createProjectModule(gomod *goModule, workingDir string, conf Config) *moduleAdapter {
	// Create a pseudo module for the main project.
	var path string
	if gomod == nil {
		path = "project"
	}

	return &moduleAdapter{
		path:		path,
		dir:		workingDir,
		gomod:		gomod,
		projectMod:	true,
		config:		conf,
	}
}
